    issue = f"original {o} at ({r},{c}) != solution {s}"
    result = {"index": box_index, "ok": False, "issue": issue}
elif not ok_set:
    # give a concise report of what's wrong: duplicates or missing
    missing = sorted(set('123456789') - set(box_digits))
    extras = sorted([d for d in box_digits if box_digits.count(d) > 1])
    # deduplicate extras for concise message
    extras = sorted(set(extras))
    issue_parts = []
    if missing:
        issue_parts.append("missing " + "".join(missing))
    if extras:
        issue_parts.append("duplicate " + "".join(extras))
